# theme colors
import re
from pptx.oxml.ns import qn
# Inspect fills/fonts on slide 2 and slide 9 shapes
for idx in [1,8]:
    slide = prs.slides[idx]
    print('---- SLIDE', idx+1, '----')
    for sh in slide.shapes:
        info=[sh.shape_type, sh.name]
        try:
            if sh.fill.type is not None and sh.fill.type==1:
                info.append('fill='+str(sh.fill.fore_color.rgb))
        except Exception as e: pass
        if sh.has_text_frame:
            for p in sh.text_frame.paragraphs:
                for r in p.runs:
                    c=''
                    try:
                        c=str(r.font.color.rgb)
                    except: pass
                    sz = r.font.size.pt if r.font.size else None
                    if r.text.strip():
                        info.append(f'run[{r.text[:20]!r} sz={sz} bold={r.font.bold} color={c} font={r.font.name}]')
        print('  ', info)
